TIMEOUT_SECONDS = 10


def extract_bearer_token(auth_header):
    if not auth_header:
        return None
    parts = auth_header.split(" ", 1)
    if len(parts) != 2 or parts[0].lower() != "bearer":
        return None
    return parts[1].strip()


def validate_jwt(token):
    try:
        unverified_header = jwt.get_unverified_header(token)
        algorithms = [unverified_header.get("alg")] if unverified_header.get("alg") else None
        claims = jwt.decode(
            token,
            options={
                "verify_signature": True,
                "verify_exp": True,
                "verify_nbf": True,
                "verify_iat": True,
                "verify_aud": False,
                "verify_iss": False,
            },
            algorithms=algorithms,
        )
        return claims, None
    except jwt.ExpiredSignatureError:
        return None, ("Token has expired", 401)
    except jwt.InvalidTokenError:
        return None, ("Invalid token", 401)


def build_upstream_headers(claims):
    headers = {}
    for header, value in request.headers.items():
        if header.lower() == "host":
            continue
        headers[header] = value

    headers["X-User-Claims"] = jwt.encode(claims, key="", algorithm="none") if claims else ""
    if "sub" in claims:
        headers["X-User-Id"] = str(claims["sub"])
    if "email" in claims:
        headers["X-User-Email"] = str(claims["email"])
    if "roles" in claims:
        roles = claims["roles"]
        if isinstance(roles, (list, tuple)):
            headers["X-User-Roles"] = ",".join(map(str, roles))
        else:
            headers["X-User-Roles"] = str(roles)
    return headers


@app.before_request
def authenticate_request():
    if request.path == "/health":
        return None

    auth_header = request.headers.get("Authorization")
    token = extract_bearer_token(auth_header)
    if not token:
        return jsonify({"error": "Missing or invalid Authorization header"}), 401

    claims, error = validate_jwt(token)
    if error:
        message, status = error
        return jsonify({"error": message}), status

    request.jwt_claims = claims
    return None


